effect.shader:
void main() {

    vec2 st = acLayerNorm;
    //st.x *= acLayerSize.x/acLayerSize.y;
    st -= vec2(0.5,0.5); //+(center/1200.0*vec2(1.,-1.));
    float tr = twirl * 0.0174533;
    float angle = atan(st.x, st.y);
    float radius = length(st);
    angle += tr*radius;
    vec2 uv = vec2( depth/radius + phase, angle/(3.1415927*2./wrap));
    if( mirror ) {
        uv = abs(mod(uv,2.0)-1.0);
    } else {
        uv = mod(uv,1.0);
    }
    uv -= 0.5;
    uv *= crop;
    uv += 0.5;
    vec4 texColor = texture2DCv(inputImg.texture,(vec4(uv,0.,1.)*acLayerToScreen).xy);

    gl_FragColor = radius > 0.5 ? vec4(0.) : mix(texColor,fogColor,clamp((1.-radius*2.)*fog,0.,1.));
}
